import{_ as i,C as s,o as n,c as d,j as r,a as o,E as a,ai as c}from"./chunks/framework.-fuqNImP.js";const w=JSON.parse('{"title":"Copilot-First Testing","description":"","frontmatter":{},"headers":[],"relativePath":"courses/copilot-first-testing.md","filePath":"courses/copilot-first-testing.md"}'),l={name:"courses/copilot-first-testing.md"};function h(u,e,p,g,m,f){const t=s("Badge");return n(),d("div",null,[e[0]||(e[0]=r("h1",{id:"copilot-first-testing",tabindex:"-1"},[o("Copilot-First Testing "),r("a",{class:"header-anchor",href:"#copilot-first-testing","aria-label":'Permalink to "Copilot-First Testing"'},"​")],-1)),a(t,{type:"warning",text:"Intermediate"}),e[1]||(e[1]=o()),a(t,{type:"info",text:"10 Modules"}),e[2]||(e[2]=o()),a(t,{type:"tip",text:"Complete"}),e[3]||(e[3]=c('<p>Master the prompt-driven testing workflow. This course teaches concepts before tools, following a research-aligned lesson order.</p><h2 id="course-overview" tabindex="-1">Course Overview <a class="header-anchor" href="#course-overview" aria-label="Permalink to &quot;Course Overview&quot;">​</a></h2><p>Where Course 1 focuses on the mechanics of Playwright, this course focuses on the <strong>thinking</strong> behind test automation. You&#39;ll learn to identify what to test, how to structure tests, and how to leverage Copilot as your primary coding assistant.</p><div class="tip custom-block"><p class="custom-block-title">Prerequisite</p><p>Complete <a href="/midnight-automation-voyage/courses/first-playwright-tests">First Playwright Tests</a> or have equivalent experience with Playwright basics.</p></div><h2 id="module-breakdown" tabindex="-1">Module Breakdown <a class="header-anchor" href="#module-breakdown" aria-label="Permalink to &quot;Module Breakdown&quot;">​</a></h2><h3 id="_1-how-automation-works" tabindex="-1">1. How Automation Works <a class="header-anchor" href="#_1-how-automation-works" aria-label="Permalink to &quot;1. How Automation Works&quot;">​</a></h3><p>The Record-Refine-Review workflow explained. Three inputs to every test: what to verify, how to find elements, and what &quot;correct&quot; looks like.</p><h3 id="_2-environment-setup" tabindex="-1">2. Environment Setup <a class="header-anchor" href="#_2-environment-setup" aria-label="Permalink to &quot;2. Environment Setup&quot;">​</a></h3><p>Detailed setup for Playwright + VS Code + Copilot. Workspace configuration, extension settings, and verification checklist.</p><h3 id="_3-test-structure" tabindex="-1">3. Test Structure <a class="header-anchor" href="#_3-test-structure" aria-label="Permalink to &quot;3. Test Structure&quot;">​</a></h3><p>Anatomy of a Playwright test — <code>test()</code>, <code>expect()</code>, <code>page</code> fixture, <code>describe</code> blocks. How test files map to features.</p><h3 id="_4-selectors-and-locators" tabindex="-1">4. Selectors and Locators <a class="header-anchor" href="#_4-selectors-and-locators" aria-label="Permalink to &quot;4. Selectors and Locators&quot;">​</a></h3><p>Deep dive into locator strategies. Priority order: <code>getByTestId</code> → <code>getByRole</code> → <code>getByLabel</code> → <code>getByText</code>. Anti-patterns to avoid.</p><h3 id="_5-what-to-automate" tabindex="-1">5. What to Automate <a class="header-anchor" href="#_5-what-to-automate" aria-label="Permalink to &quot;5. What to Automate&quot;">​</a></h3><p>Decision framework for automation candidates. High-value patterns (regression, smoke, data-driven) vs. low-value targets (exploratory, visual-only).</p><h3 id="_6-your-testing-toolkit" tabindex="-1">6. Your Testing Toolkit <a class="header-anchor" href="#_6-your-testing-toolkit" aria-label="Permalink to &quot;6. Your Testing Toolkit&quot;">​</a></h3><p>Playwright&#39;s built-in tools — codegen, trace viewer, HTML reporter, VS Code extension. When to use each.</p><h3 id="_7-record-and-refine" tabindex="-1">7. Record and Refine <a class="header-anchor" href="#_7-record-and-refine" aria-label="Permalink to &quot;7. Record and Refine&quot;">​</a></h3><p>Full Record-Refine-Review cycle with guided examples. Record against the practice app, then systematically improve.</p><h3 id="_8-writing-tests-from-scratch" tabindex="-1">8. Writing Tests from Scratch <a class="header-anchor" href="#_8-writing-tests-from-scratch" aria-label="Permalink to &quot;8. Writing Tests from Scratch&quot;">​</a></h3><p>Move beyond recording — write tests from acceptance criteria. Structure, assertions, error handling.</p><h3 id="_9-page-object-model" tabindex="-1">9. Page Object Model <a class="header-anchor" href="#_9-page-object-model" aria-label="Permalink to &quot;9. Page Object Model&quot;">​</a></h3><p>Encapsulate page interactions in reusable classes. Reduce duplication, improve maintainability, and make tests self-documenting.</p><h3 id="_10-api-testing" tabindex="-1">10. API Testing <a class="header-anchor" href="#_10-api-testing" aria-label="Permalink to &quot;10. API Testing&quot;">​</a></h3><p>Playwright&#39;s <code>request</code> API for backend testing. Authentication tokens, API assertions, and combining UI + API tests.</p><h2 id="concept-→-tool-mapping" tabindex="-1">Concept → Tool Mapping <a class="header-anchor" href="#concept-→-tool-mapping" aria-label="Permalink to &quot;Concept → Tool Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Concept</th><th>Playwright Feature</th></tr></thead><tbody><tr><td>1</td><td>Automation workflow</td><td><code>codegen</code>, test runner</td></tr><tr><td>3</td><td>Test structure</td><td><code>test()</code>, <code>describe()</code>, <code>expect()</code></td></tr><tr><td>4</td><td>Element selection</td><td>Locator API, <code>getByTestId()</code></td></tr><tr><td>6</td><td>Tool awareness</td><td>Trace viewer, HTML reporter</td></tr><tr><td>7</td><td>Recording</td><td><code>npx playwright codegen</code></td></tr><tr><td>9</td><td>Code organization</td><td>Page Object classes</td></tr><tr><td>10</td><td>API testing</td><td><code>request</code> fixture, <code>APIRequestContext</code></td></tr></tbody></table><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/midnight-automation-voyage/courses/build-skills">Build Skills</a> — auth fixtures, visual regression, CI/CD</li><li><a href="/midnight-automation-voyage/courses/go-pro">Go Pro</a> — advanced topics for team leads</li></ul>',29))])}const k=i(l,[["render",h]]);export{w as __pageData,k as default};
